description:
**Implementation in krkn-operator pkg:**

Create a reusable function to sync ConfigMap to kvstore that can be used by all operators in the ecosystem.

**1. Create new package** (pkg/configmap/sync.go):
```go
package configmap

import (
    "strings"
    corev1 "k8s.io/api/core/v1"
    "github.com/krkn-chaos/krkn-operator/pkg/configstore"
)

// SyncConfigMapToStore parses a ConfigMap and syncs values to configstore
// For keys named 'config.yaml', parses content as KEY,VALUE pairs line by line
// For other keys, stores them as-is
// Returns error if parsing fails
func SyncConfigMapToStore(configMap *corev1.ConfigMap, store configstore.Store) error {
    if configMap == nil {
        return fmt.Errorf("configMap is nil")
    }

    for key, value := range configMap.Data {
        if key == "config.yaml" {
            // Parse config.yaml line by line
            lines := strings.Split(value, "\n")
            for _, line := range lines {
                line = strings.TrimSpace(line)
                if line == "" {
                    continue
                }
                // Split by comma: KEY,VALUE
                parts := strings.SplitN(line, ",", 2)
                if len(parts) != 2 {
                    continue // Skip invalid lines
                }
                configKey := strings.TrimSpace(parts[0])
                configValue := strings.TrimSpace(parts[1])
                store.SetValue(configKey, configValue)
            }
        } else {
            // Store other keys as-is
            store.SetValue(key, value)
        }
    }
    return nil
}
```

**2. Write tests** (pkg/configmap/sync_test.go):
```go
package configmap

import (
    "testing"
    corev1 "k8s.io/api/core/v1"
    metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
    "github.com/krkn-chaos/krkn-operator/pkg/configstore"
)

func TestSyncConfigMapToStore(t *testing.T) {
    tests := []struct {
        name          string
        configMap     *corev1.ConfigMap
        expectedStore map[string]string
        expectError   bool
    }{
        {
            name: "valid config.yaml with multiple lines",
            configMap: &corev1.ConfigMap{
                ObjectMeta: metav1.ObjectMeta{Name: "test"},
                Data: map[string]string{
                    "config.yaml": "KEY1,value1\nKEY2,value2",
                },
            },
            expectedStore: map[string]string{
                "KEY1": "value1",
                "KEY2": "value2",
            },
        },
        {
            name: "config.yaml with empty lines and invalid format",
            configMap: &corev1.ConfigMap{
                ObjectMeta: metav1.ObjectMeta{Name: "test"},
                Data: map[string]string{
                    "config.yaml": "KEY1,value1\n\ninvalid-line\nKEY2,value2",
                },
            },
            expectedStore: map[string]string{
                "KEY1": "value1",
                "KEY2": "value2",
            },
        },
        {
            name: "other configmap keys stored as-is",
            configMap: &corev1.ConfigMap{
                ObjectMeta: metav1.ObjectMeta{Name: "test"},
                Data: map[string]string{
                    "operator-name": "krkn-operator",
                    "namespace": "default",
                },
            },
            expectedStore: map[string]string{
                "operator-name": "krkn-operator",
                "namespace": "default",
            },
        },
        {
            name:        "nil configmap returns error",
            configMap:   nil,
            expectError: true,
        },
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            store := configstore.NewMockStore() // You may need to create a mock
            err := SyncConfigMapToStore(tt.configMap, store)

            if tt.expectError {
                if err == nil {
                    t.Error("expected error but got nil")
                }
                return
            }

            if err != nil {
                t.Errorf("unexpected error: %v", err)
            }

            for key, expectedValue := range tt.expectedStore {
                value, ok := store.GetValue(key)
                if !ok {
                    t.Errorf("key %s not found in store", key)
                    continue
                }
                if value != expectedValue {
                    t.Errorf("key %s: got %s, want %s", key, value, expectedValue)
                }
            }
        })
    }
}
```

**3. Update ConfigMapReconciler** in krkn-operator:
Replace inline parsing logic with:
```go
import "github.com/krkn-chaos/krkn-operator/pkg/configmap"

func (r *ConfigMapReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
    logger := log.FromContext(ctx)
    store := kvstore.Get()

    // Fetch ConfigMap
    cm := &corev1.ConfigMap{}
    if err := r.Get(ctx, req.NamespacedName, cm); err != nil {
        if errors.IsNotFound(err) {
            return ctrl.Result{}, nil
        }
        return ctrl.Result{}, err
    }

    // Sync to store
    if err := configmap.SyncConfigMapToStore(cm, store); err != nil {
        logger.Error(err, "failed to sync configmap to store")
        return ctrl.Result{}, err
    }

    logger.Info("synced configmap to store", "name", cm.Name)
    return ctrl.Result{}, nil
}
```

**4. Add startup initialization** (cmd/main.go):
```go
import "github.com/krkn-chaos/krkn-operator/pkg/configmap"

// After manager setup, before starting controllers:
func initializeConfigStore(mgr ctrl.Manager) error {
    ctx := context.Background()
    logger := mgr.GetLogger()

    cm := &corev1.ConfigMap{}
    err := mgr.GetClient().Get(ctx, types.NamespacedName{
        Name:      "krkn-operator-config",
        Namespace: "krkn-operator-system",
    }, cm)

    if err != nil {
        if errors.IsNotFound(err) {
            logger.Info("config configmap not found, kvstore not initialized")
            return nil // Not an error, configmap might not exist yet
        }
        return fmt.Errorf("failed to get config configmap: %w", err)
    }

    store := kvstore.Get()
    if err := configmap.SyncConfigMapToStore(cm, store); err != nil {
        return fmt.Errorf("failed to sync configmap to store: %w", err)
    }

    logger.Info("kvstore initialized from configmap")
    return nil
}

// In main():
if err := initializeConfigStore(mgr); err != nil {
    setupLog.Error(err, "failed to initialize configstore")
    os.Exit(1)
}
```

